function FadeIn({children,delay=0,dir="up"}){
  const r=useRef(null);
  const[v,setV]=useState(false);
  useEffect(()=>{
    const o=new IntersectionObserver(([e])=>{if(e.isIntersecting)setV(true);},{threshold:.07});
    if(r.current)o.observe(r.current);
    return()=>o.disconnect();
  },[]);
  const t=dir==="left"?(v?"translateX(0)":"translateX(-36px)"):dir==="right"?(v?"translateX(0)":"translateX(36px)"):(v?"translateY(0)":"translateY(24px)");
  return <div ref={r} style={{opacity:v?1:0,transform:t,transition:"opacity .6s ease "+delay+"s,transform .6s ease "+delay+"s"}}>{children}</div>;
}

function useDraw(){
  const r=useRef(null);
  const[d,setD]=useState(false);
  useEffect(()=>{
    const o=new IntersectionObserver(([e])=>{if(e.isIntersecting)setTimeout(()=>setD(true),80);},{threshold:.2});
    if(r.current)o.observe(r.current);
    return()=>o.disconnect();
  },[]);
  const ln=(dl=0,len=280)=>({strokeDasharray:len,strokeDashoffset:d?0:len,transition:"stroke-dashoffset 1.1s ease "+dl+"s"});
  const ac=(dl=0,rv=50)=>{const c=2*Math.PI*rv;return{strokeDasharray:c,strokeDashoffset:d?0:c,transition:"stroke-dashoffset 1s ease "+dl+"s"};};
  const fd=(dl=0)=>({opacity:d?1:0,transition:"opacity .7s ease "+dl+"s"});
  return{ref:r,d,ln,ac,fd};
}


function Wheel(){
  const{ref,ln,ac,fd}=useDraw();
  const C="#3b82f6",D="#60a5fa",Hi="#93c5fd";
  const cx=145,cy=145,tR=124,rimR=102,barR=95,boreR=13;
  const ci=r=>2*Math.PI*r;
  return(
    <div ref={ref} style={{width:"100%",maxWidth:360}}>
      <svg viewBox="0 0 290 290" style={{width:"100%",overflow:"visible"}}>
        {Array.from({length:8}).map((_,i)=><line key={"gx"+i} x1={i*42} y1={0} x2={i*42} y2={290} stroke={C} strokeWidth={.18} opacity={.15}/>)}
        {Array.from({length:8}).map((_,i)=><line key={"gy"+i} x1={0} y1={i*42} x2={290} y2={i*42} stroke={C} strokeWidth={.18} opacity={.15}/>)}
        <circle cx={cx} cy={cy} r={tR} fill={"rgba(59,130,246,.04)"} stroke={C} strokeWidth={1.1} style={ac(0,tR)}/>
        <circle cx={cx} cy={cy} r={tR-8} fill="none" stroke={C} strokeWidth={.5} style={ac(.04,tR-8)}/>
        {Array.from({length:32}).map((_,i)=>{
          const a=(i/32)*2*Math.PI,w=.07;
          return(
            <g key={i}>
              <line x1={cx+Math.cos(a-w)*(tR-1)} y1={cy+Math.sin(a-w)*(tR-1)} x2={cx+Math.cos(a-w)*(tR-9)} y2={cy+Math.sin(a-w)*(tR-9)} stroke={C} strokeWidth={.45} style={ln(.03+i*.003,10)}/>
              <line x1={cx+Math.cos(a+w)*(tR-1)} y1={cy+Math.sin(a+w)*(tR-1)} x2={cx+Math.cos(a+w)*(tR-9)} y2={cy+Math.sin(a+w)*(tR-9)} stroke={C} strokeWidth={.45} style={ln(.03+i*.003,10)}/>
            </g>
          );
        })}
        <circle cx={cx} cy={cy} r={rimR} fill={"rgba(59,130,246,.07)"} stroke={C} strokeWidth={.9} style={ac(.07,rimR)}/>
        <circle cx={cx} cy={cy} r={rimR-4} fill="none" stroke={C} strokeWidth={.35} style={ac(.09,rimR-4)}/>
        <circle cx={cx} cy={cy} r={barR} fill={"rgba(59,130,246,.10)"} stroke={Hi} strokeWidth={.7} style={ac(.11,barR)}/>
        {Array.from({length:5}).map((_,i)=>{
          const base=(i/5)*2*Math.PI-1.57;
          const lA=base-.20,rA=base+.20,tlA=base-.065,trA=base+.065;
          const R=barR-4,sr=30;
          const pts=[
            (cx+Math.cos(lA)*sr)+","+(cy+Math.sin(lA)*sr),
            (cx+Math.cos(lA)*(R*.55))+","+(cy+Math.sin(lA)*(R*.55)),
            (cx+Math.cos(tlA)*R)+","+(cy+Math.sin(tlA)*R),
            (cx+Math.cos(trA)*R)+","+(cy+Math.sin(trA)*R),
            (cx+Math.cos(rA)*(R*.55))+","+(cy+Math.sin(rA)*(R*.55)),
            (cx+Math.cos(rA)*sr)+","+(cy+Math.sin(rA)*sr),
          ].join(" ");
          const mR=R*.62;
          return(
            <g key={i}>
              <polygon points={pts} fill={"rgba(59,130,246,.16)"} stroke={C} strokeWidth={.7} style={fd(.18+i*.07)}/>
              <line x1={cx+Math.cos(base)*sr} y1={cy+Math.sin(base)*sr} x2={cx+Math.cos(base)*(R-.5)} y2={cy+Math.sin(base)*(R-.5)} stroke={Hi} strokeWidth={.5} strokeDasharray="3 2" style={fd(.22+i*.07)}/>
              <ellipse cx={cx+Math.cos(base)*mR} cy={cy+Math.sin(base)*mR} rx={7} ry={12} fill={"rgba(59,130,246,.06)"} stroke={C} strokeWidth={.4} transform={"rotate("+((base*180/3.14159)+90)+" "+(cx+Math.cos(base)*mR)+" "+(cy+Math.sin(base)*mR)+")"} style={fd(.26+i*.07)}/>
            </g>
          );
        })}
        <circle cx={cx} cy={cy} r={32} fill={"rgba(59,130,246,.1)"} stroke={C} strokeWidth={.8} style={ac(.5,32)}/>
        <circle cx={cx} cy={cy} r={22} fill={"rgba(59,130,246,.18)"} stroke={Hi} strokeWidth={1} style={ac(.53,22)}/>
        <circle cx={cx} cy={cy} r={boreR} fill={"rgba(59,130,246,.25)"} stroke={C} strokeWidth={.8} style={ac(.56,boreR)}/>
        <circle cx={cx} cy={cy} r={7} fill={"rgba(59,130,246,.32)"} stroke={Hi} strokeWidth={.5} style={ac(.58,7)}/>
        {Array.from({length:5}).map((_,i)=>{
          const a=(i/5)*2*Math.PI-1.57;
          const bxp=cx+Math.cos(a)*28,byp=cy+Math.sin(a)*28;
          return(
            <g key={i}>
              <circle cx={bxp} cy={byp} r={5.5} fill={"rgba(59,130,246,.2)"} stroke={C} strokeWidth={.7} style={ac(.60+i*.04,5.5)}/>
              <circle cx={bxp} cy={byp} r={2.5} fill={"rgba(59,130,246,.35)"} stroke={Hi} strokeWidth={.5} style={ac(.63+i*.04,2.5)}/>
            </g>
          );
        })}
        <line x1={cx} y1={cy-tR-8} x2={cx} y2={cy+tR+8} stroke={D} strokeWidth={.3} strokeDasharray="6 4" style={fd(.75)}/>
        <line x1={cx-tR-8} y1={cy} x2={cx+tR+8} y2={cy} stroke={D} strokeWidth={.3} strokeDasharray="6 4" style={fd(.75)}/>
        <g style={fd(.85)}>
          <line x1={cx-tR} y1={cy+tR+16} x2={cx+tR} y2={cy+tR+16} stroke={D} strokeWidth={.5}/>
          <line x1={cx-tR} y1={cy+tR+12} x2={cx-tR} y2={cy+tR+20} stroke={D} strokeWidth={.5}/>
          <line x1={cx+tR} y1={cy+tR+12} x2={cx+tR} y2={cy+tR+20} stroke={D} strokeWidth={.5}/>
          <text x={cx} y={cy+tR+27} textAnchor="middle" fill={D} fontSize={7} fontFamily="monospace">678mm O.D. / 18in RIM</text>
          <text x={cx+4} y={cy-32} fill={D} fontSize={6.5} fontFamily="monospace" opacity={.8}>PCD 114.3mm</text>
        </g>
        <text x={cx} y={283} textAnchor="middle" fill={C} fontSize={8} fontFamily="monospace" letterSpacing={2} style={fd(.5)}>18in ALLOY WHEEL - FRONT VIEW</text>
        <text x={cx} y={291} textAnchor="middle" fill={D} fontSize={6.5} fontFamily="monospace" opacity={.5} style={fd(.55)}>REF: AMC-WHL-002 // 5x114.3</text>
      </svg>
    </div>
  );
}

