function PortCard({src,label,sub,featured=false,setLb}){
  const r=useRef(null);const[v,setV]=useState(false);const[h,setH]=useState(false);
  useEffect(()=>{const o=new IntersectionObserver(([e])=>{if(e.isIntersecting)setV(true);},{threshold:.05});if(r.current)o.observe(r.current);return()=>o.disconnect();},[]);
  return(
    <div ref={r} onClick={()=>setLb({src,label,sub})}
      onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)}
      style={{opacity:v?1:0,transform:v?"translateY(0)":"translateY(20px)",transition:"opacity .55s ease,transform .55s ease",position:"relative",overflow:"hidden",aspectRatio:featured?"16/10":"4/3",background:"#0e0e0e",cursor:"zoom-in"}}>
      <img src={src} alt={label} style={{width:"100%",height:"100%",objectFit:"cover",transform:h?"scale(1.05)":"scale(1)",transition:"transform .5s ease",display:"block"}}/>
      <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(0,0,0,.78) 0%,transparent 55%)",opacity:h?1:0,transition:"opacity .3s ease"}}/>
      <div style={{position:"absolute",bottom:0,left:0,right:0,padding:"14px 16px",opacity:h?1:0,transform:h?"translateY(0)":"translateY(8px)",transition:"opacity .3s,transform .3s"}}>
        <p style={{fontFamily:"Bebas Neue,sans-serif",fontSize:featured?15:13,letterSpacing:2,color:"#f0ece4",margin:0}}>{label}</p>
        {sub&&<p style={{fontFamily:"DM Sans,sans-serif",fontSize:10,color:"#999",margin:"2px 0 0"}}>{sub}</p>}
      </div>
      <div style={{position:"absolute",top:0,left:0,width:3,height:h?"100%":"0%",background:"#C0392B",transition:"height .4s ease"}}/>
    </div>
  );
}
